set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>
<title>Real Bank - No Changes Detected</title>

<style>
*{
margin:0;
padding:0;
box-sizing:border-box;
font-family:'Segoe UI',Arial,sans-serif;
}

body{
background:#eef3f8;
padding:30px;
color:#333;
}

.wrapper{
max-width:760px;
margin:auto;
background:#fff;
border-radius:18px;
overflow:hidden;
box-shadow:0 15px 35px rgba(0,0,0,.15);
}

.header{
background:linear-gradient(135deg,#F57C00,#FB8C00,#FFB300);
padding:40px;
text-align:center;
color:white;
}

.logo{
font-size:36px;
font-weight:bold;
}

.tagline{
margin-top:8px;
font-size:15px;
opacity:.9;
}

.hero{
padding:35px;
background:#FFF8E8;
text-align:center;
}

.hero h2{
color:#E65100;
margin-bottom:15px;
font-size:30px;
}

.hero p{
font-size:15px;
line-height:28px;
color:#555;
}

.info{
margin:25px;
padding:20px;
background:#FFF3CD;
border-left:6px solid #FF9800;
border-radius:10px;
font-size:16px;
font-weight:bold;
color:#A65A00;
}

.card{
margin:30px;
border:1px solid #E5E5E5;
border-radius:15px;
overflow:hidden;
}

.card-title{
background:#FF9800;
color:white;
padding:18px;
font-size:20px;
font-weight:bold;
}

table{
width:100%;
border-collapse:collapse;
}

td{
padding:18px;
border-bottom:1px solid #EEEEEE;
}

td:first-child{
width:38%;
background:#FAFAFA;
font-weight:bold;
color:#555;
}

.acc{
font-size:22px;
font-weight:bold;
color:#0056B3;
}

.status{
background:#FFF3CD;
color:#B26A00;
padding:6px 18px;
border-radius:20px;
font-weight:bold;
}

.note{
margin:0 30px 30px;
padding:22px;
background:#FFF8E8;
border-left:6px solid orange;
border-radius:10px;
}

.note h3{
margin-bottom:12px;
color:#C97B00;
}

.note li{
margin:10px 0;
}

.footer{
background:#002B5B;
padding:35px;
text-align:center;
color:white;
}

.footer p{
line-height:24px;
font-size:13px;
}

.support{
margin-top:20px;
padding-top:20px;
border-top:1px solid rgba(255,255,255,.2);
}
</style>

</head>

<body>

<div class='wrapper'>

<div class='header'>

<div class='logo'>
🏦 REAL BANK
</div>

<div class='tagline'>
Safe • Secure • Trusted Banking
</div>

</div>

<div class='hero'>

<h2>
ℹ No Changes Detected
</h2>

<p>

The information submitted is identical to the data already available in your account.

No update was required.

</p>

</div>

<div class='info'>

⚠ Requested data is already updated with the same details.

</div>

<div class='card'>

<div class='card-title'>
📋 Existing Account Details
</div>

<table>

<tr>
<td>💳 Account Number</td>
<td class='acc'>" ++ (vars.accountNumber default "") ++ "</td>
</tr>

<tr>
<td>👤 Customer Name</td>
<td>" ++ ((payload.FULLNAME[0]) default "") ++ "</td>
</tr>

<tr>
<td>📱 Mobile Number</td>
<td>" ++ ((payload.MOBILENUMBER[0]) default "") ++ "</td>
</tr>

<tr>
<td>📍 Address</td>
<td>" ++ ((payload.ADDRESS[0]) default "") ++ "</td>
</tr>

<tr>
<td>✅ Account Status</td>
<td><span class='status'>" ++ ((payload.STATUS[0]) default "") ++ "</span></td>
</tr>

<tr>
<td>📅 Account Created On</td>
<td>" ++ (((payload.CREATED_AT[0]) as String) default "") ++ "</td>
</tr>

<tr>
<td>Status Code</td>
<td>200</td>
</tr>

<tr>
<td>Update Status</td>
<td><span class='status'>NO CHANGES</span></td>
</tr>

</table>

</div>

<div class='note'>

<h3>💡 Information</h3>

<ul>

<li>Your request was successfully processed.</li>

<li>No changes were applied because the submitted values already match our records.</li>

<li>If you wish to update your profile, please provide different information.</li>

<li>If you believe this is incorrect, contact Real Bank Customer Support.</li>

</ul>

</div>

<div class='footer'>

<h3>

Thank You For Banking With Us ❤️

</h3>

<p>

Customer Care : +91 9494207062

<br>

Email : narsingbeesetti22@gmail.com

<br><br>

© 2026 Real Bank

<br>

Safe Banking | Digital Banking | Secure Transactions

</p>

<div class='support'>

This is an automated email. Please do not reply.

</div>

</div>

</div>

</body>

</html>"]
